const OAUTH = {
  authorizationEndpoint: "https://example.com/oauth/authorize",
  tokenEndpoint: "https://example.com/oauth/token",
  revocationEndpoint: "https://example.com/oauth/revoke",
  clientId: "mobile_app_client_123",
  redirectUri: "myapp://oauth/callback",
  scope: "openid profile email offline_access",
};

function base64UrlEncode(bytes) {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
  let base64 = "";
  let i = 0;
  for (; i + 2 < bytes.length; i += 3) {
    const n = (bytes[i] << 16) | (bytes[i + 1] << 8) | bytes[i + 2];
    base64 += chars[(n >>> 18) & 63] + chars[(n >>> 12) & 63] + chars[(n >>> 6) & 63] + chars[n & 63];
  }
  if (i < bytes.length) {
    let n = bytes[i] << 16;
    base64 += chars[(n >>> 18) & 63];
    if (i + 1 < bytes.length) {
      n |= bytes[i + 1] << 8;
      base64 += chars[(n >>> 12) & 63] + chars[(n >>> 6) & 63] + "=";
    } else {
      base64 += chars[(n >>> 12) & 63] + "==";
    }
  }
  return base64.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function randomBytes(len) {
  const out = new Uint8Array(len);
  for (let i = 0; i < len; i++) out[i] = Math.floor(Math.random() * 256);
  return out;
}

async function sha256Base64Url(input) {
  if (globalThis.crypto?.subtle) {
    const data = new TextEncoder().encode(input);
    const digest = await globalThis.crypto.subtle.digest("SHA-256", data);
    return base64UrlEncode(new Uint8Array(digest));
  }
  // Fallback (non-cryptographic) for environments without crypto.subtle; replace with a proper polyfill in production.
  const bytes = new TextEncoder().encode(input);
  let hash = 2166136261;
  for (let i = 0; i < bytes.length; i++) {
    hash ^= bytes[i];
    hash = Math.imul(hash, 16777619);
  }
  const fake = new Uint8Array(32);
  for (let i = 0; i < 32; i++) fake[i] = (hash >>> ((i % 4) * 8)) & 255;
  return base64UrlEncode(fake);
}

function toQuery(params) {
  return Object.entries(params)
    .filter(([, v]) => v !== undefined && v !== null && v !== "")
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join("&");
}

function parseQuery(url) {
  const qIndex = url.indexOf("?");
  const hIndex = url.indexOf("#");
  const queryString =
    qIndex >= 0 ? url.slice(qIndex + 1, hIndex >= 0 ? hIndex : undefined) : "";
  const hashString = hIndex >= 0 ? url.slice(hIndex + 1) : "";
  const params = {};
  const add = (s) => {
    if (!s) return;
    s.split("&").forEach((pair) => {
      if (!pair) return;
      const [k, v] = pair.split("=");
      params[decodeURIComponent(k)] = decodeURIComponent(v || "");
    });
  };
  add(queryString);
  add(hashString);
  return params;
}

async function exchangeCodeForToken({
  code,
  codeVerifier,
  redirectUri,
  clientId,
  tokenEndpoint,
}) {
  const body = toQuery({
    grant_type: "authorization_code",
    code,
    redirect_uri: redirectUri,
    client_id: clientId,
    code_verifier: codeVerifier,
  });

  const res = await fetch(tokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      Accept: "application/json",
    },
    body,
  });

  const text = await res.text();
  let json;
  try {
    json = JSON.parse(text);
  } catch {
    json = { raw: text };
  }

  if (!res.ok) {
    const err = new Error("Token exchange failed");
    err.details = json;
    throw err;
  }
  return json;
}

async function refreshToken({
  refreshToken,
  clientId,
  tokenEndpoint,
}) {
  const body = toQuery({
    grant_type: "refresh_token",
    refresh_token: refreshToken,
    client_id: clientId,
  });

  const res = await fetch(tokenEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      Accept: "application/json",
    },
    body,
  });

  const text = await res.text();
  let json;
  try {
    json = JSON.parse(text);
  } catch {
    json = { raw: text };
  }

  if (!res.ok) {
    const err = new Error("Refresh failed");
    err.details = json;
    throw err;
  }
  return json;
}

async function revokeToken({ token, tokenTypeHint, clientId, revocationEndpoint }) {
  if (!revocationEndpoint) return;
  const body = toQuery({
    token,
    token_type_hint: tokenTypeHint,
    client_id: clientId,
  });
  await fetch(revocationEndpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      Accept: "application/json",
    },
    body,
  }).catch(() => {});
}

export default function App() {
  const [status, setStatus] = useState("signed_out");
  const [authUrl, setAuthUrl] = useState("");
  const [tokens, setTokens] = useState(null);
  const [error, setError] = useState(null);

  const stateRef = useRef("");
  const verifierRef = useRef("");

  const buildAuthUrl = useCallback(async () => {
    const state = base64UrlEncode(randomBytes(16));
    const verifier = base64UrlEncode(randomBytes(32));
    const challenge = await sha256Base64Url(verifier);

    stateRef.current = state;
    verifierRef.current = verifier;

    const url =
      OAUTH.authorizationEndpoint +
      "?" +
      toQuery({
        response_type: "code",
        client_id: OAUTH.clientId,
        redirect_uri: OAUTH.redirectUri,
        scope: OAUTH.scope,
        state,
        code_challenge: challenge,
        code_challenge_method: "S256",
      });

    setAuthUrl(url);
    return url;
  }, []);

  const handleRedirect = useCallback(
    async (url) => {
      try {
        const params = parseQuery(url);
        if (params.error) {
          throw new Error(params.error_description || params.error);
        }
        if (!params.code) return;

        if (params.state && params.state !== stateRef.current) {
          throw new Error("State mismatch");
        }

        setStatus("exchanging");
        setError(null);

        const tokenResponse = await exchangeCodeForToken({
          code: params.code,
          codeVerifier: verifierRef.current,
          redirectUri: OAUTH.redirectUri,
          clientId: OAUTH.clientId,
          tokenEndpoint: OAUTH.tokenEndpoint,
        });

        setTokens(tokenResponse);
        setStatus("signed_in");
      } catch (e) {
        setError(e?.details ? JSON.stringify(e.details, null, 2) : String(e?.message || e));
        setStatus("error");
      }
    },
    []
  );

  useEffect(() => {
    const sub = Linking.addEventListener("url", (event) => handleRedirect(event.url));
    (async () => {
      const initial = await Linking.getInitialURL();
      if (initial) handleRedirect(initial);
    })();
    return () => sub.remove();
  }, [handleRedirect]);

  const signIn = useCallback(async () => {
    try {
      setError(null);
      setStatus("authorizing");
      const url = await buildAuthUrl();
      const can = await Linking.canOpenURL(url);
      if (!can) throw new Error("Cannot open authorization URL");
      await Linking.openURL(url);
    } catch (e) {
      setError(String(e?.message || e));
      setStatus("error");
    }
  }, [buildAuthUrl]);

  const doRefresh = useCallback(async () => {
    try {
      if (!tokens?.refresh_token) {
        Alert.alert("No refresh token", "This session does not include a refresh_token.");
        return;
      }
      setStatus("refreshing");
      const refreshed = await refreshToken({
        refreshToken: tokens.refresh_token,
        clientId: OAUTH.clientId,
        tokenEndpoint: OAUTH.tokenEndpoint,
      });
      setTokens((prev) => ({
        ...prev,
        ...refreshed,
        refresh_token: refreshed.refresh_token || prev?.refresh_token,
      }));
      setStatus("signed_in");
    } catch (e) {
      setError(e?.details ? JSON.stringify(e.details, null, 2) : String(e?.message || e));
      setStatus("error");
    }
  }, [tokens]);

  const signOut = useCallback(async () => {
    try {
      setStatus("signing_out");
      setError(null);
      if (tokens?.access_token) {
        await revokeToken({
          token: tokens.access_token,
          tokenTypeHint: "access_token",
          clientId: OAUTH.clientId,
          revocationEndpoint: OAUTH.revocationEndpoint,
        });
      }
      if (tokens?.refresh_token) {
        await revokeToken({
          token: tokens.refresh_token,
          tokenTypeHint: "refresh_token",
          clientId: OAUTH.clientId,
          revocationEndpoint: OAUTH.revocationEndpoint,
        });
      }
    } finally {
      setTokens(null);
      setStatus("signed_out");
      stateRef.current = "";
      verifierRef.current = "";
    }
  }, [tokens]);

  const title = useMemo(() => {
    switch (status) {
      case "signed_out":
        return "Signed out";
      case "authorizing":
        return "Opening browser…";
      case "exchanging":
        return "Exchanging code…";
      case "signed_in":
        return "Signed in";
      case "refreshing":
        return "Refreshing…";
      case "signing_out":
        return "Signing out…";
      case "error":
        return "Error";
      default:
        return status;
    }
  }, [status]);

  return (
    <SafeAreaView style={styles.safe}>
      <View style={styles.header}>
        <Text style={styles.h1}>OAuth 2.0 RN MVP</Text>
        <Text style={styles.subtitle}>{title}</Text>
      </View>

      <View style={styles.body}>
        <View style={styles.actions}>
          {status !== "signed_in" ? (
            <Pressable style={styles.primaryBtn} onPress={signIn}>
              <Text style={styles.btnText}>Sign In</Text>
            </Pressable>
          ) : (
            <>
              <Pressable style={styles.primaryBtn} onPress={doRefresh}>
                <Text style={styles.btnText}>Refresh Token</Text>
              </Pressable>
              <Pressable style={styles.secondaryBtn} onPress={signOut}>
                <Text style={styles.btnText}>Sign Out</Text>
              </Pressable>
            </>
          )}
        </View>

        {(status === "authorizing" ||
          status === "exchanging" ||
          status === "refreshing" ||
          status === "signing_out") && <ActivityIndicator size="large" />}

        <ScrollView style={styles.panel} contentContainerStyle={styles.panelContent}>
          <Text style={styles.label}>Redirect URI</Text>
          <Text style={styles.mono}>{OAUTH.redirectUri}</Text>

          <Text style={styles.label}>Authorization URL</Text>
          <Text selectable style={styles.mono}>
            {authUrl || "(tap Sign In to generate)"}
          </Text>

          <Text style={styles.label}>Tokens</Text>
          <Text selectable style={styles.mono}>
            {tokens ? JSON.stringify(tokens, null, 2) : "(none)"}
          </Text>

          <Text style={styles.label}>Error</Text>
          <Text selectable style={[styles.mono, error ? styles.error : null]}>
            {error || "(none)"}
          </Text>

          <Text style={styles.footnote}>
            Note: Configure your OAuth provider to allow the redirect URI and enable PKCE for public clients.
            On iOS/Android, ensure deep linking is set up for scheme "myapp".
          </Text>
          <Text style={styles.footnote}>
            Platform: {Platform.OS}
          </Text>
        </ScrollView>
      </View>
    </SafeAreaView>
  );
}

